---
import config from 'virtual:starlight/user-config';
import type { Props } from '@astrojs/starlight/props';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';

import LanguageSelect from 'virtual:starlight/components/LanguageSelect';
import Search from 'virtual:starlight/components/Search';
import SiteTitle from 'virtual:starlight/components/SiteTitle';
import SocialIcons from 'virtual:starlight/components/SocialIcons';
import ThemeSelect from 'virtual:starlight/components/ThemeSelect';

import Banner from './Banner.astro';

// Read the SKF version from the root package.json at build time.
// This is the same source of truth `npm version` bumps and `npm publish` uses,
// so the displayed version matches what's deployed on npm after each release.
const pkgPath = fileURLToPath(new URL('../../../package.json', import.meta.url));
const { version } = JSON.parse(readFileSync(pkgPath, 'utf8'));

/**
 * Render the `Search` component if Pagefind is enabled or the default search component has been overridden.
 */
const shouldRenderSearch =
	config.pagefind || config.components.Search !== '@astrojs/starlight/components/Search.astro';
---

